```go
func flatten(input []interface{}) []interface{} {
	var result []interface{}
	for _, item := range input {
		if nested, ok := item.([]interface{}); ok {
			result = append(result, flatten(nested)...)
		} else {
			result = append(result, item)
		}
	}
	return result
}
